script.text:
      &JavascriptReportInit;
      /* <flatten type="Javascript"> */
function load$Grid(g) {
  g._$p = g._getColumnOrder('ky');
  g._$y = g._getColumnOrder('nam');
  g._$c = g._getColumnOrder('ma_so');
  g._$u = g._getColumnOrder('ma_dvcs');
  g._$tien = g._getColumnOrder('tien');

  g.add_onResponseComplete(on$GridCalculateValueOfFinancialArticles$ResponseComplete);
  g.add_commandEvent(on$GridCalculateValueOfFinancialArticles$ExecuteCommand);
  g.add_itemValueChanged(onChange$GridCalculateValueOfFinancialArticles$);
}

function dispose$Grid(g) {
  g._arrValue = null;
  try {g.remove_commandEvent(on$GridCalculateValueOfFinancialArticles$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridCalculateValueOfFinancialArticles$ResponseComplete);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridCalculateValueOfFinancialArticles$);} catch (ex) {}
}

function on$GridCalculateValueOfFinancialArticles$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'Save':
      request$Posting(g, action);
      break;
    case 'Calcutate':
      if(g._rowCount == 0) return;
      var r = (g._activeCell ? g._activeRow : 1), o = g._getItemValue(r, g._$p);
      o.row = r;
      var q = [];
        Array.add(q, ['ma_dvcs', 'String', g._unit]);
        Array.add(q, ['tu_ky', 'String', g._periodFrom]);
        Array.add(q, ['tu_nam', 'String', g._yearFrom]);
        Array.add(q, ['den_ky', 'String', g._periodTo]);
        Array.add(q, ['den_nam', 'String', g._yearTo]);
        g.request(o, 'Calcutate', 'Calcutate', q);
        q = [];
      break;
    default:
      break;
  }
}

function request$Posting(g, c) {
  if (g._rowCount == 0 || g._arrValue.length == 0) return;
  var count = 4000, concurrent = 10, temp = '', q = '', index = 0, arr = [], maxlength = g._arrValue.length;
  for (var i = 0; i < g._arrValue.length; i ++) {
    temp = g._arrValue[i][0] + String.fromCharCode(255) + g._arrValue[i][1];
    if ((q + temp).toString().length <= count) q = q + (q == '' ? '' : ',') + temp;
    else {
      arr[arr.length] = q;
      q = temp;
    }
  }

  if (q != '') arr[arr.length] = q;
  var r = (g._activeCell ? g._activeRow : 1), o = g._getItemValue(r, g._$c), str = [], length = arr.length;
  o.row = r;
  g._finish = (parseInt(length / concurrent)) + ((length % concurrent == 0) ? 0 : 1);

  for (i = 0; i < length; i ++) {
    if (index == concurrent) {
      index = 0;
      g.request(o, c, c, str);
      str.splice(0, concurrent);
    }
    index ++;
    Array.add(str, ['k' + index, 'String', arr[i]);
  }

  if (index <= concurrent && index > 0) {
    for (index += 1; index <= concurrent; index ++) {Array.add(str, ['k' + index, 'String', '');}
    g.request(o, c, c, str);
  }
  arr = str = [];
}

function onChange$GridCalculateValueOfFinancialArticles$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'tien':
      addArray(g);
      break;
    default:
      break;
  }
}

function on$GridCalculateValueOfFinancialArticles$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm, id = g.get_id(), v = g._language == 'v';
  var m1 = v ? 'Chương trình đã thực hiện xong.' : 'The process was completed successfully.', m2 = v ? 'Phát sinh lỗi trong quá trình thực hiện.' : 'The process was failed.';
  switch (context) {
    case 'Save':
      g._finish --;
      if(result[0].Value == '') {
        if (g._finish == 0){
          g._arrValue = [];
          $message.show(m1, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
        }
      }
      else $message.show(m2, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      break;
    case 'Calcutate':
      if(result[0].Value == '') $message.show(m1, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
        else $message.show(m2, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      break;
    default:
      break;
  }
}

function addArray(g) {
  var period = g._getItemValue(g._activeRow, g._$p);
  var key = g._getItemValue(g._activeRow, g._$y) + ((period < 10 ? '0' : '') + period) + String.fromCharCode(255) + g._getItemValue(g._activeRow, g._$c) + String.fromCharCode(255) + g._getItemValue(g._activeRow, g._$u);
  var v = g._getItemValue(g._activeRow, g._$tien), add = false;
  var item = [key, v];
  for (var i = 0; i < g._arrValue.length; i ++) {
    if (g._arrValue[i][0] == key) {
      g._arrValue[i] = item;
      add = true;
      return;
    }
  }
  if (!add) Array.add(g._arrValue, item);
}
function fill$Grid(g) {
  if(g._gridRefresh) {
    g._arrValue = [];
    g._gridRefresh = false;
    return;
  }
  if (g._arrValue.length == 0) return;

  var period;
  for (var r = 1; r <= g._rowCount; r++) {
    for (var row = 0; row < g._arrValue.length; row++) {
      period = g._getItemValue(r, g._$p);
      if (g._arrValue[row][0] == (g._getItemValue(r, g._$y) + ((period < 10 ? '0' : '') + period) + String.fromCharCode(255) + g._getItemValue(r, g._$c) + String.fromCharCode(255) + g._getItemValue(r, g._$u))) {
        g._setItemValue(r, g._$tien, g._arrValue[row][1]);
      }
    }
  }
}
function readOnlyCell(g) {
  var l1 = g._getColumnOrder('tien'), l2 = g._getColumnOrder('kind');
  for (i = 1; i <= g._rowCount; i++){
    if (g._getItemValue(i, l2) != '9'){
      var o = g._getItem(i, l1);
      if ($func.isIF) o.readOnly = true;
        else $addHandler(o, "keydown", readOnlyHandler);
    }
  }
}
function readOnlyHandler(e) {
  var k = $func.keyCode(e);
  if (k != 13 && !($func.isNavKey(e))) $func.cancelEvent(e);
}
/* </flatten> */
